function fileHash(p) {
  if (!fs.existsSync(p)) return null;
  const data = fs.readFileSync(p);
  let h = 2166136261;
  for (let i = 0; i < data.length; i++) {
    h ^= data[i];
    h = Math.imul(h, 16777619);
  }
  return (h >>> 0).toString(16);
}

